import React, { useState } from 'react';
import { taskService } from '../services/taskService';

export function TaskForm({ onTaskAdded }) {
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [dueDate, setDueDate] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    if (!title.trim()) {
      setError('Title is required');
      return;
    }

    setLoading(true);
    setError('');

    try {
      const newTask = {
        title: title.trim(),
        description: description.trim(),
        dueDate: dueDate || null,
      };

      const createdTask = await taskService.createTask(newTask);
      
      setTitle('');
      setDescription('');
      setDueDate('');
      
      if (onTaskAdded) {
        onTaskAdded(createdTask);
      }
    } catch (err) {
      setError('Failed to create task. Please try again.');
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="card p-6 mb-6 animate-slide-in">
      <h2 className="text-2xl font-bold text-gray-800 mb-4">✏️ Add New Task</h2>
      
      {error && (
        <div className="mb-4 p-4 bg-red-50 border-l-4 border-red-500 text-red-700 rounded">
          {error}
        </div>
      )}

      <form onSubmit={handleSubmit} className="space-y-4">
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">
            Task Title
          </label>
          <input
            type="text"
            value={title}
            onChange={(e) => setTitle(e.target.value)}
            placeholder="What needs to be done?"
            className="input-field"
            disabled={loading}
          />
        </div>

        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">
            Description
          </label>
          <textarea
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            placeholder="Add more details (optional)"
            className="input-field h-24 resize-none"
            disabled={loading}
          />
        </div>

        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">
            Due Date
          </label>
          <input
            type="date"
            value={dueDate}
            onChange={(e) => setDueDate(e.target.value)}
            className="input-field"
            disabled={loading}
          />
          <p className="text-xs text-gray-500 mt-1">💡 Priority will be auto-assigned based on due date and keywords</p>
        </div>

        <button
          type="submit"
          disabled={loading}
          className="btn-primary w-full"
        >
          {loading ? '⏳ Creating...' : '➕ Add Task'}
        </button>
      </form>
    </div>
  );
}
